<?php
namespace App\Http\Controllers\Api\Admin\Marketing;
use App\Http\Controllers\Concerns\ApiResponses; use App\Http\Controllers\Controller; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB;
class AbandonedCartAdminController extends Controller { use ApiResponses; public function index(Request $r): JsonResponse { return $this->success(DB::table('abandoned_carts')->orderByDesc('id')->paginate((int)$r->query('per_page',25))); } public function show(int $id): JsonResponse { return $this->success(['cart'=>DB::table('abandoned_carts')->find($id),'items'=>DB::table('abandoned_cart_items')->where('abandoned_cart_id',$id)->get(),'reminders'=>DB::table('abandoned_cart_reminders')->where('abandoned_cart_id',$id)->get()]); } public function sendReminder(int $id): JsonResponse { DB::table('abandoned_cart_reminders')->insert(['abandoned_cart_id'=>$id,'channel'=>'email','reminder_number'=>1,'status'=>'queued','scheduled_at'=>now(),'created_at'=>now(),'updated_at'=>now()]); return $this->success(['message'=>'Reminder queued; provider sending remains safe-mode until enabled.']); } public function report(): JsonResponse { return $this->success(['open'=>DB::table('abandoned_carts')->where('status','open')->count(),'recovered_revenue'=>DB::table('abandoned_cart_recoveries')->sum('recovered_revenue')]); } }
